declare class AuthenticationError extends Error {
    code: string;
    constructor(message: string, code?: string);
}
declare class NetworkError extends AuthenticationError {
    originalError: unknown;
    constructor(message: string, originalError?: unknown);
}
declare class TimeoutError extends AuthenticationError {
    constructor(message: string);
}
declare class ApiError extends Error {
    statusCode: number;
    data: unknown;
    constructor(message: string, statusCode: number, data?: unknown);
}
/**
 * Thrown when a required parameter is missing or fails a format check before the
 * request is dispatched (e.g. invalid email/domain in a suppression entry).
 */
declare class ValidationError extends Error {
    constructor(message: string);
}
export { AuthenticationError, NetworkError, TimeoutError, ApiError, ValidationError };
